import java.util.*
import kotlin.math.sqrt

data class Query(val index: Int, val l: Int, val r: Int, val threshold: Int)

fun solve(nums: Array<Long>, queries: Array<Array<Long>>): Array<Long> {
    val n = nums.size
    val q = queries.size
    val qList = Array(q) { i ->
        val l = queries[i][0].toInt()
        val r = queries[i][1].toInt()
        val threshold = queries[i][2].toInt()
        Query(i, l, r, threshold)
    }
    val blockSize = sqrt(n.toDouble()).toInt()
    qList.sortWith(compareBy<Query> { it.l / blockSize }.thenBy { it.r })
    val ans = Array(q) { 0L }
    var left = 0
    var right = -1
    val freqMap = HashMap<Long, Int>()
    val freqGroup = HashMap<Int, TreeSet<Long>>()
    val activeFreqs = TreeSet<Int>()

    fun add(x: Long) {
        val oldFreq = freqMap.getOrDefault(x, 0)
        val newFreq = oldFreq + 1
        if (oldFreq > 0) {
            val set = freqGroup[oldFreq]!!
            set.remove(x)
            if (set.isEmpty()) {
                freqGroup.remove(oldFreq)
                activeFreqs.remove(oldFreq)
            }
        }
        freqMap[x] = newFreq
        val newSet = freqGroup.getOrPut(newFreq) { TreeSet() }
        newSet.add(x)
        activeFreqs.add(newFreq)
    }

    fun remove(x: Long) {
        val oldFreq = freqMap[x]!!
        val newFreq = oldFreq - 1
        val oldSet = freqGroup[oldFreq]!!
        oldSet.remove(x)
        if (oldSet.isEmpty()) {
            freqGroup.remove(oldFreq)
            activeFreqs.remove(oldFreq)
        }
        if (newFreq == 0) {
            freqMap.remove(x)
        } else {
            freqMap[x] = newFreq
            val newSet = freqGroup.getOrPut(newFreq) { TreeSet() }
            newSet.add(x)
            activeFreqs.add(newFreq)
        }
    }

    for (query in qList) {
        val (qIndex, l, r, threshold) = query
        while (right < r) {
            add(nums[++right])
        }
        while (right > r) {
            remove(nums[right--])
        }
        while (left < l) {
            remove(nums[left++])
        }
        while (left > l) {
            add(nums[--left])
        }
        if (activeFreqs.isEmpty()) {
            ans[qIndex] = -1
        } else {
            val maxF = activeFreqs.last()
            if (maxF < threshold) {
                ans[qIndex] = -1
            } else {
                val candidateSet = freqGroup[maxF]!!
                ans[qIndex] = candidateSet.first()
            }
        }
    }
    return ans
}
```

### Explanation
1. **Query Processing**: The queries are sorted using Mo's Algorithm to minimize pointer movements. Each query is processed by adjusting the current segment (defined by `left` and `right` pointers) to match the query's subarray.
2. **Data Maintenance**: 
   - **`freqMap`** tracks the frequency of each element in the current segment.
   - **`freqGroup`** maintains a sorted set (TreeSet) of elements for each frequency, allowing efficient access to the smallest element for any frequency.
   - **`activeFreqs`** is a sorted set of frequencies that currently have at least one element, facilitating quick retrieval of the maximum frequency.
3. **Adjustment Operations**: 
   - **`add(x)`** increments the frequency of `x`, updates `freqGroup`, and ensures `activeFreqs` reflects the new frequency.
   - **`remove(x)`** decrements the frequency of `x`, updates the data structures, and cleans up if frequencies become zero.
4. **Answer Extraction**: For each query, after adjusting the segment, the maximum frequency in `activeFreqs` is checked against the threshold. If it meets or exceeds the threshold, the smallest element with this frequency is selected; otherwise, -1 is returned.

This approach efficiently handles the constraints by leveraging Mo's Algorithm and optimized data structures for frequency tracking and element retrieval.

