    for (query in queries) {
        val l = query[0].toInt()
        val r = query[1].toInt()
        val threshold = query[2]
        val subArray = nums.slice(l..r)
        val frequencyMap = mutableMapOf<Long, Long>()
        for (num in subArray) {
            frequencyMap[num] = frequencyMap.getOrDefault(num, 0) + 1
        }
        val candidates = frequencyMap.filter { it.value >= threshold }
        if (candidates.isEmpty()) {
            result.add(-1)
        } else {
            val maxFreq = candidates.maxBy { it.value }.value
            val maxCandidates = candidates.filter { it.value == maxFreq }
            result.add(maxCandidates.minBy { it.key }.key)
        }
    }
    return result.toTypedArray()
